import React from "react";

const typeDescriptions = {
  ENFP: "სხარტი, ენერგიული და ინოვაციური ადამიანი, რომელიც მარტივად ახდენს ურთიერთობებს.",
  ISTJ: "კარგი ორგანიზატორი, დეტალებზე ორიენტირებული და პასუხისმგებელი.",
  // დაამატე ყველა 16 ტიპის მოკლე აღწერა
};

export default function FinalResult({ results }) {
  const type =
    (results.EI || "") +
    (results.SN || "") +
    (results.TF || "") +
    (results.JP || "");

  return (
    <div className="test-card">
      <h2>{type}</h2>

      <img
        src={`/images/types/${type}.png`}
        alt={type}
        style={{ maxWidth: "200px", marginBottom: "20px" }}
      />

      <p style={{ marginBottom: "20px" }}>
        {typeDescriptions[type] || "ეს არის მოკლე აღწერა თქვენს ფსიქოტიპზე."}
      </p>

      <p>
        მეტი ინფორმაციისთვის გადადით{" "}
        <a href="/articles">მიმოხილვების</a> გვერდზე
      </p>
    </div>
  );
}
